/* ══════════════════════════════════════════════════════
   FALLBACK formato moneda (usa cop() de catalogo.js si existe)
   ══════════════════════════════════════════════════════ */
function _cop(n) {
  return typeof cop === 'function' ? cop(n) : ('$' + Number(n).toLocaleString('es-CO'));
}

/* ══════════════════════════════════════════════════════
   NORMALIZAR CLAVE: limpia espacios y mayúsculas para buscar en PRECIOS_PVP
   ══════════════════════════════════════════════════════ */
function _normKey(s) {
  return (s || '').replace(/\s+/g, ' ').trim().toUpperCase();
}

/* ══════════════════════════════════════════════════════
   BUSCAR PRECIOS PVP para un nombreProducto dado
   Intenta coincidencia exacta primero, luego por prefijo de 20 chars
   Devuelve: [{tipo, precio}] o null
   ══════════════════════════════════════════════════════ */
function _buscarPrecios(nombreProducto) {
  if (!nombreProducto) return null;
  var k = _normKey(nombreProducto);

  /* 1. Exacto */
  if (PRECIOS_PVP[k]) return _toArray(PRECIOS_PVP[k]);
  /* 2. Clave del mapa empieza con los primeros 20 chars del nombreProducto */
  var prefix = k.substring(0, 22);
  var keys = Object.keys(PRECIOS_PVP);
  for (var i = 0; i < keys.length; i++) {
    if (keys[i].indexOf(prefix) === 0 && prefix.length > 10) {
      return _toArray(PRECIOS_PVP[keys[i]]);
    }
  }
  /* 3. nombreProducto empieza con los primeros 20 chars de la clave */
  for (var j = 0; j < keys.length; j++) {
    var kp = keys[j].substring(0, 22);
    if (kp.length > 10 && k.indexOf(kp) === 0) {
      return _toArray(PRECIOS_PVP[keys[j]]);
    }
  }
  return null;
}

function _toArray(obj) {
  return Object.keys(obj).map(function(tipo) {
    return { tipo: tipo, precio: obj[tipo] };
  });
}

/* ══════════════════════════════════════════════════════
   getPresentacionesLab
   Dado un producto y un nombre de laboratorio (variantes[i].laboratorio),
   busca el lab en producto.laboratorios y devuelve sus precios PVP del Informe.
   ══════════════════════════════════════════════════════ */
function getPresentacionesLab(producto, labNombre) {
  if (!producto || !producto.laboratorios || !labNombre) return null;

  var labNorm = labNombre.toLowerCase().replace(/[\s.]+/g, '');
  var mejorLab = null;

  /* Buscar en producto.laboratorios el que coincida con labNombre */
  var claves = Object.keys(producto.laboratorios);
  for (var i = 0; i < claves.length; i++) {
    var lab = producto.laboratorios[claves[i]];
    var nombreNorm = (lab.nombre || '').toLowerCase().replace(/[\s.]+/g, '');
    var claveNorm  = claves[i].toLowerCase().replace(/_/g, '');
    if (nombreNorm.indexOf(labNorm) !== -1 || labNorm.indexOf(claveNorm) !== -1 ||
        claveNorm.indexOf(labNorm) !== -1) {
      mejorLab = lab;
      break;
    }
  }

  if (!mejorLab) return null;

  /* Buscar los precios PVP reales en el mapa del Informe */
  var pvp = _buscarPrecios(mejorLab.nombreProducto);
  if (pvp && pvp.length > 0) return pvp;

  /* Si no encontró en el Informe, usar los precios que ya tiene el laboratorio */
  if (mejorLab.precios) {
    return Object.keys(mejorLab.precios).map(function(k) {
      return { tipo: mejorLab.precios[k].label || k, precio: mejorLab.precios[k].precio };
    });
  }

  return null;
}

/* ══════════════════════════════════════════════════════
   calcularPrecioLaboratorio
   Devuelve el primer precio PVP del laboratorio, o precioBase si no hay datos.
   ══════════════════════════════════════════════════════ */
function calcularPrecioLaboratorio(precioBase, laboratorio, producto) {
  if (typeof precioBase !== 'number') return 0;
  if (!laboratorio || !producto) return precioBase;
  var pres = getPresentacionesLab(producto, laboratorio);
  if (!pres || pres.length === 0) return precioBase;
  return pres[0].precio;
}

/* ══════════════════════════════════════════════════════
   actualizarPresentacionesUI
   Actualiza los botones de "Vender Por" en card y modal
   con los precios PVP del laboratorio seleccionado.
   ══════════════════════════════════════════════════════ */
function actualizarPresentacionesUI(prodId, labNombre) {
  if (typeof CATALOGO === 'undefined') return;
  var producto = CATALOGO.find(function(x) { return x.id === prodId; });
  if (!producto) return;

  var presLab = getPresentacionesLab(producto, labNombre);
  if (!presLab || presLab.length === 0) return;

  /* ── Card (grilla) ── */
  var grid = document.getElementById('productosGrid');
  var card = grid ? grid.querySelector('[data-id="' + prodId + '"]') : null;
  if (card) {
    var btns = card.querySelectorAll('.btn-pres-precio');
    presLab.forEach(function(pr, i) {
      if (btns[i]) {
        var tipoEl   = btns[i].querySelector('.bpp-tipo');
        var precioEl = btns[i].querySelector('.bpp-precio');
        if (tipoEl)   tipoEl.textContent   = pr.tipo;
        if (precioEl) precioEl.textContent = _cop(pr.precio);
        btns[i].setAttribute('onclick',
          'event.stopPropagation();selPresentacion(' + prodId + ',' + i + ')');
      }
    });
    var selEl    = card.querySelector('#precio-pres-' + prodId);
    var footerEl = document.getElementById('precio-' + prodId);
    if (selEl)    selEl.textContent    = _cop(presLab[0].precio);
    if (footerEl) footerEl.textContent = _cop(presLab[0].precio);
  }

  /* ── Modal (si está abierto) ── */
  var modalGrid = document.getElementById('modalPresbtns');
  if (modalGrid) {
    var modalBtns = modalGrid.querySelectorAll('.modal-pres-pill');
    presLab.forEach(function(pr, i) {
      if (modalBtns[i]) {
        var tipoEl   = modalBtns[i].querySelector('.mpp-tipo');
        var precioEl = modalBtns[i].querySelector('.mpp-precio');
        if (tipoEl)   tipoEl.textContent   = pr.tipo;
        if (precioEl) precioEl.textContent = _cop(pr.precio);
        modalBtns[i].setAttribute('onclick',
          'selPresentacionModal(' + prodId + ',' + i + ')');
      }
    });
    var modalPrecio = document.getElementById('modalPrecioVal');
    var modalLabel  = document.getElementById('modalPrecioLabel');
    if (modalPrecio) modalPrecio.textContent = _cop(presLab[0].precio);
    if (modalLabel)  modalLabel.textContent  = '/ ' + presLab[0].tipo;
  }
}

/* ══════════════════════════════════════════════════════
   PATCH: interceptar selVariante / selVarianteModal
   para actualizar precios cuando el usuario cambie de laboratorio
   ══════════════════════════════════════════════════════ */
function _patchearSelectores() {
  var _orig      = window.selVariante;
  var _origModal = window.selVarianteModal;

  if (typeof _orig === 'function') {
    window.selVariante = function(id, idx) {
      _orig(id, idx);
      if (typeof CATALOGO !== 'undefined') {
        var p = CATALOGO.find(function(x) { return x.id === id; });
        if (p && p.variantes && p.variantes[idx] && p.variantes[idx].laboratorio) {
          actualizarPresentacionesUI(id, p.variantes[idx].laboratorio);
        }
      }
    };
  }

  if (typeof _origModal === 'function') {
    window.selVarianteModal = function(prodId, vi) {
      _origModal(prodId, vi);
      if (typeof CATALOGO !== 'undefined') {
        var p = CATALOGO.find(function(x) { return x.id === prodId; });
        if (p && p.variantes && p.variantes[vi] && p.variantes[vi].laboratorio) {
          actualizarPresentacionesUI(prodId, p.variantes[vi].laboratorio);
        }
      }
    };
  }
}

/* ══════════════════════════════════════════════════════
   INIT AL CARGAR LA PÁGINA
   Precarga los precios PVP en las presentaciones de cada
   producto según el laboratorio activo (variante[0] por defecto)
   ══════════════════════════════════════════════════════ */
function _inicializarPrecios() {
  if (typeof CATALOGO === 'undefined') return;

  CATALOGO.forEach(function(p) {
    if (!p.variantes || !p.laboratorios) return;
    var vi = 0; /* laboratorio por defecto: el primero */
    var v  = p.variantes[vi];
    if (!v || !v.laboratorio) return;

    var presLab = getPresentacionesLab(p, v.laboratorio);
    if (!presLab || presLab.length === 0) return;

    /* Actualizar presentaciones[] del producto con los precios PVP reales */
    if (!p.presentaciones || p.presentaciones.length === 0) {
      p.presentaciones = presLab;
    } else {
      /* Mezclar: mantener los tipos existentes pero actualizar precios */
      presLab.forEach(function(pr) {
        var exist = p.presentaciones.find(function(ex) {
          return ex.tipo.toLowerCase().indexOf(pr.tipo.toLowerCase().substring(0, 5)) !== -1 ||
                 pr.tipo.toLowerCase().indexOf(ex.tipo.toLowerCase().substring(0, 5)) !== -1;
        });
        if (exist) {
          exist.precio = pr.precio; /* actualizar precio con PVP real */
        } else {
          p.presentaciones.push(pr); /* agregar presentación nueva del lab */
        }
      });
    }
  });
}

/* ══════════════════════════════════════════════════════
   Exponer al scope global y ejecutar al cargar
   ══════════════════════════════════════════════════════ */
if (typeof window !== 'undefined') {
  window.calcularPrecioLaboratorio  = calcularPrecioLaboratorio;
  window.getPresentacionesLab       = getPresentacionesLab;
  window.actualizarPresentacionesUI = actualizarPresentacionesUI;

  window.addEventListener('DOMContentLoaded', function() {
    /* Primero inicializar precios, luego parchear los selectores */
    _inicializarPrecios();
    setTimeout(_patchearSelectores, 80);
  });
}